"use client";
import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "../../lib/utils";
import { createExpressiveClasses } from "../../utils/expressive-design";

const cardVariants = cva(
  "rounded-lg border bg-card text-card-foreground shadow-sm",
  {
    variants: {
      elevation: {
        default: "",
        resting: "elevation-resting",
        hovered: "elevation-hovered",
        pressed: "elevation-pressed",
        focused: "elevation-focused",
        elevated: "elevation-elevated",
        success: "elevation-success",
        warning: "elevation-warning",
        error: "elevation-error",
      },
      status: {
        default: "",
        success: "status-success",
        warning: "status-warning",
        error: "status-error",
        info: "status-info",
        neutral: "status-neutral",
      },
      interactive: {
        default: "",
        true: "cursor-pointer transition-all duration-200",
      },
    },
    defaultVariants: {
      elevation: "default",
      status: "default",
      interactive: "default",
    },
  }
);

export interface CardProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof cardVariants> {}

const Card = React.forwardRef<HTMLDivElement, CardProps>(
  ({ className, elevation, status, interactive, ...props }, ref) => {
    let enhancedClasses = "";
    if (elevation || status || interactive) {
      enhancedClasses = createExpressiveClasses({
        status: status || undefined,
        elevation: elevation || undefined,
        interactive: Boolean(interactive),
      });
    }

    return (
      <div
        ref={ref}
        className={cn(
          cardVariants({ elevation, status, interactive }),
          enhancedClasses,
          className
        )}
        {...props}
      />
    );
  }
);
Card.displayName = "Card";

const CardHeader = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("flex flex-col space-y-1.5 p-6", className)}
    {...props}
  />
));
CardHeader.displayName = "CardHeader";

const CardTitle = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("text-2xl font-semibold leading-none tracking-tight", className)}
    {...props}
  />
));
CardTitle.displayName = "CardTitle";

const CardDescription = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("text-sm text-muted-foreground", className)}
    {...props}
  />
));
CardDescription.displayName = "CardDescription";

const CardContent = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div ref={ref} className={cn("p-6 pt-0", className)} {...props} />
));
CardContent.displayName = "CardContent";

const CardFooter = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("flex items-center p-6 pt-0", className)}
    {...props}
  />
));
CardFooter.displayName = "CardFooter";

export { Card, CardHeader, CardFooter, CardTitle, CardDescription, CardContent, cardVariants };